// Compact problem definitions - starter code is auto-generated
export interface CompactProblem {
  t: string; // title
  d: 'E' | 'M' | 'H'; // difficulty
  desc: string; // description
  fn: string; // function name (JS style camelCase)
  params: string; // param names comma-separated
  ret: string; // return type hint
  ex: { i: string; o: string; e?: string }[]; // examples
  tc: { i: string; o: string }[]; // test cases
  con: string[]; // constraints
  cat: string; // category
}

